import Card from '@mui/material/Card'
import React from 'react'
import CharacterView from '../atoms/CharacterView'
import useCheckStore from '../../store/useCheckStore';
import { useTranslation } from 'react-i18next';
import { getManifestStatus, getManifestStep } from '../../util/func';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import { styled } from '@mui/material';

const ButtonItem = styled(Button)(({
    flexGrow: 1,
    flexBasis: 0,
}));

const CharacterManifest: React.FC<CharacterInfo> = (info) => {

    const { inven, manifest, addManifest, removeManifest } = useCheckStore();
    const { t } = useTranslation()

    const status = t(getManifestStatus(info, inven))
    const stepArr = info.tags.includes("manifest.step2") ? [0, 1, 2] : [0, 1]

    const currentStep = getManifestStep(info, manifest)

    const changeManifest = (step: number) => {
        if (step === 0) removeManifest(info.id)
        else addManifest(step * 10000 + info.id)
    }

    return (
        <Card sx={{ display: 'flex', overflow: "unset", alignItems: "stretch" }}>
            <CharacterView info={info} disabled />
            {status === "manifest.available"
                ? stepArr.map((step) => (<ButtonItem
                    key={step}
                    variant={currentStep === step ? "contained" : undefined}
                    color={currentStep === step ? "info" : undefined}
                    onClick={() => changeManifest(step)}
                >
                    {t(`manifest.step${step}`)}
                </ButtonItem>))
                : <Typography sx={{ ml: 1, display: "flex", alignItems: "center" }}>{status}</Typography>}
        </Card >
    )
}

export default CharacterManifest