import React from 'react'
import useCheckStore from '../../store/useCheckStore'
import { useTranslation } from 'react-i18next';
import { Box, ImageListItem, ImageListItemBar, useTheme } from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import { getShortName, styleIcon } from '../../util/func';

interface CharacterViewProps {
    info: CharacterInfo;
    disabled?: boolean;
}

// 캐릭터 조회 UI
const CharacterView: React.FC<CharacterViewProps> = ({ info, disabled = false }) => {

    const { inven } = useCheckStore();
    const { t, i18n } = useTranslation()
    const theme = useTheme()

    const name = t(`c${info.code}`);
    const checked = inven.includes(info.id);

    return (
        <Box
            sx={{
                minWidth: 75,
                maxWidth: 75,
                cursor: disabled ? "unset" : "pointer",
                position: "relative",
            }}
        >
            {styleIcon(info)}
            <ImageListItem >
                <img
                    src={`/image/data/${info.id}.png`}
                    alt={name}
                    style={{
                        borderRadius: "5px",
                        boxSizing: "border-box",
                        pointerEvents: "none",
                    }}
                />
                {checked ?
                    <CheckCircleIcon color="info" fontSize='large'
                        sx={{
                            position: "absolute",
                            right: -5,
                            top: -5,
                            zIndex: 1,
                            backgroundColor: theme.palette.background.paper,
                            borderRadius: "100px",
                        }}
                    />
                    : null}
                <ImageListItemBar subtitle={getShortName(name, i18n.language)} sx={{
                    height: 22,
                    "& .MuiImageListItemBar-subtitle": {
                        textAlign: "center",
                        fontSize: "12px",
                    },
                    ".MuiImageListItemBar-titleWrap": {
                        padding: 0.5
                    }
                }} />
            </ImageListItem>
        </Box>
    )
}

export default CharacterView